import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"角色概述","description":"","frontmatter":{},"headers":[],"relativePath":"guide/characters.md","filePath":"guide/characters.md","lastUpdated":1781112327000}'),o={name:"guide/characters.md"};function h(n,t,s,i,l,c){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="角色概述" tabindex="-1">角色概述 <a class="header-anchor" href="#角色概述" aria-label="Permalink to &quot;角色概述&quot;">​</a></h1><h2 id="等级" tabindex="-1">等级 <a class="header-anchor" href="#等级" aria-label="Permalink to &quot;等级&quot;">​</a></h2><p>角色最高等级为 <strong>60 级</strong>，每升 1 级所需经验逐级提高。</p><h2 id="角色定位" tabindex="-1">角色定位 <a class="header-anchor" href="#角色定位" aria-label="Permalink to &quot;角色定位&quot;">​</a></h2><p>游戏中角色按功能分为五个定位：</p><table tabindex="0"><thead><tr><th>定位</th><th>英文</th><th>特点</th></tr></thead><tbody><tr><td>核心</td><td>Core</td><td>极高输出，相对脆弱</td></tr><tr><td>先锋</td><td>Vanguard</td><td>中上等攻防，先发制人</td></tr><tr><td>近卫</td><td>Guardian</td><td>极高生命和护甲，专注保护</td></tr><tr><td>支援</td><td>Support</td><td>提供增益/减益，身板较脆</td></tr><tr><td>治疗</td><td>Medic</td><td>治疗和防御，身板较脆</td></tr></tbody></table><h2 id="能力值总览" tabindex="-1">能力值总览 <a class="header-anchor" href="#能力值总览" aria-label="Permalink to &quot;能力值总览&quot;">​</a></h2><p>角色能力值分为 <strong>基础能力值</strong> 和 <strong>额外能力值</strong>：</p><ul><li><strong>基础能力值</strong>：基于初始属性、核心属性、等级计算</li><li><strong>额外能力值</strong>：通过装备、技能等方式获得</li></ul><blockquote><p>所有百分比加成的能力值乘算，都基于角色的基础能力值计算。</p></blockquote><table tabindex="0"><thead><tr><th>能力值</th><th>说明</th><th>有初始值</th></tr></thead><tbody><tr><td>生命值 (HP)</td><td>角色生存能力</td><td>✅</td></tr><tr><td>魔法值 (MP)</td><td>释放魔法消耗</td><td>✅</td></tr><tr><td>爆发能量</td><td>战技/爆发技消耗，最大 200</td><td>—</td></tr><tr><td>行动速度</td><td>转化为行动系数</td><td>✅</td></tr><tr><td>攻击力</td><td>物理伤害基础</td><td>✅</td></tr><tr><td>物理护甲</td><td>转化为物理伤害减免</td><td>✅</td></tr><tr><td>魔法抗性</td><td>直接参与魔法伤害减免</td><td>—</td></tr><tr><td>加速系数</td><td>削减吟唱时间</td><td>—</td></tr><tr><td>闪避率</td><td>普通攻击闪避检定</td><td>—</td></tr><tr><td>暴击率</td><td>初始 5%</td><td>—</td></tr><tr><td>暴击伤害</td><td>初始 125%</td><td>—</td></tr><tr><td>物理穿透</td><td>削减目标护甲</td><td>—</td></tr><tr><td>魔法穿透</td><td>削减目标魔法抗性</td><td>—</td></tr><tr><td>冷却缩减</td><td>减少技能冷却时间</td><td>—</td></tr><tr><td>生命回复</td><td>时间流逝时回复</td><td>✅</td></tr><tr><td>魔法回复</td><td>时间流逝时回复</td><td>✅</td></tr><tr><td>攻击距离</td><td>战棋地图上的施法距离</td><td>—</td></tr><tr><td>移动距离</td><td>战棋地图上的移动范围</td><td>—</td></tr></tbody></table>',11)])])}const _=d(o,[["render",h]]);export{p as __pageData,_ as default};
